      <div class="blob"></div>
      <div class="blob-2"></div>
    </div>
    !-->
    <div id="nav">
      <a id="nav-home" @click="$refs.fullpage.api.moveTo(1)">{{
        $t("home.name")
      }}</a>
      <a id="nav-about" @click="$refs.fullpage.api.moveTo(2)">{{
        $t("about.name")
      }}</a>
      <a id="nav-projects" @click="$refs.fullpage.api.moveTo(3)">{{
        $t("projects.name")
      }}</a>
      <a id="nav-skills" @click="$refs.fullpage.api.moveTo(4)">{{
        $t("skills.name")
      }}</a>
      <a id="nav-contact" @click="$refs.fullpage.api.moveTo(5)">{{
        $t("contact.name")
      }}</a>
    </div>

    <div class="lang-picker" v-if="$i18n.locale == 'en'">
      <button class="lang-picker-button" v-on:click="changeLanguage('en')">
        EN
      </button>
      <div class="lang-picker-content">
        <a v-on:click="changeLanguage('de')">DE</a>
      </div>
    </div>

    <div class="lang-picker" v-else>
      <button class="lang-picker-button" v-on:click="changeLanguage('de')">
        DE
      </button>
      <div class="lang-picker-content">
        <a v-on:click="changeLanguage('en')">EN</a>
      </div>
    </div>

    <full-page ref="fullpage" :options="options" id="fullpage">
      <div class="section">
        <div class="title">
          <h1>Marc Baumann</h1>
          <h2>{{ $t("home.title") }}</h2>
          <p>
            {{ $t("home.tutorial") }}
          </p>
        </div>
      </div>
      <div class="section">
        <h3>{{ $t("about.name") }}</h3>
        <div class="cards-container"></div>
        <div class="card">
          <h3>{{ $t("about.personalInformations.title") }}</h3>
          <div>
            <p>
              <b>{{ $t("about.personalInformations.name") }}:</b>
              <span>Marc Nicolas Baumann</span>
            </p>
            <p>
              <b>{{ $t("about.personalInformations.email") }}:</b>
              <span>marc.baumann@swisscom.com</span>
            </p>
            <p>
              <b>{{ $t("about.personalInformations.birthday") }}:</b>
              <span>08.10.2002</span>
            </p>
            <p>
              <b>{{ $t("about.personalInformations.nationality[0]") }}:</b>
              <span>{{ $t("about.personalInformations.nationality[1]") }}</span>
            </p>
            <p>
              <b>{{ $t("about.personalInformations.formation[0]") }}:</b>
              <span>{{ $t("about.personalInformations.formation[1]") }}</span>
              <br />
              <span>{{ $t("about.personalInformations.formation[2]") }}</span>
            </p>
            <br />
            <p>
              <b>{{ $t("about.personalInformations.school[0]") }}:</b>
              <span>{{ $t("about.personalInformations.school[1]") }}</span>
              <br />
              <span>{{ $t("about.personalInformations.school[2]") }}</span>
            </p>
            <br />
            <br />
            <p v-html="$t('about.personalInformations.more')"></p>
          </div>
          <h3>{{ $t("about.hobbies.title") }}</h3>
          <div>
            <h4>{{ $t("about.hobbies.music[0]") }}</h4>
            <p>
              {{ $t("about.hobbies.music[1]") }}
            </p>
            <h4>{{ $t("about.hobbies.travel[0]") }}</h4>
            <p>
              {{ $t("about.hobbies.travel[1]") }}
            </p>
            <h4>{{ $t("about.hobbies.others[0]") }}</h4>
            <p>
              {{ $t("about.hobbies.others[1]") }}
            </p>
          </div>
          <h3>{{ $t("about.aboutThisSite.title") }}</h3>
          <div>
            <p>
              {{ $t("about.aboutThisSite.description") }}
            </p>
            <p>{{ $t("about.aboutThisSite.state") }}</p>
          </div>
        </div>
      </div>
      <div class="section">
        <h1
          style="top: 120px; left: 50%; transform: translateX(-50%); position: absolute"
        >
          {{ $t("projects.name") }}
        </h1>
        <div class="slide" v-for="(project, index) in projects" :key="index">
          <div class="project-card">
            <h3>
              {{ project.name
              }}<span style="float: right">{{ project.date }}</span>
            </h3>
            <p v-html="project.description"></p>
          </div>
        </div>
      </div>
      <div class="section">
        <div class="skillTitle">
          <h3>{{ $t("skills.title") }}</h3>
          <p>{{ $t("skills.disclaimer") }}</p>
          <div class="search-area">
            <input
              class="search"
              v-model="search"
              v-on:keyup="checkSearch()"
              :placeholder="$t('skills.search')"
            />
            <div class="dropdown">
              <button class="dropbtn">
                {{ selectedFilter }}
                <img
                  class="clear"
                  src="./assets/icons/close.png"
                  v-on:click="selectedFilter = $t('skills.filter')"
                />
              </button>
              <div class="dropdown-content fp-scrollable">
                <a
                  v-for="(filter, index) in generateFilter()"
                  :key="index"
                  v-on:click="selectedFilter = filter"
                  >{{ filter }}</a
                >
              </div>
            </div>
          </div>
        </div>
        <div class="skillContainer">
          <div v-for="(skill, index) in skills" :key="index">
            <div class="skill tooltip" v-if="checkFilters(skill)">
              {{ skill.name }}
              <span class="tooltiptext">{{ skill.description }}</span>
            </div>
          </div>
        </div>
      </div>
      <div class="section">
        <h3>{{ $t("contact.title") }}</h3>
        <!--<form
          action="mailto:marc.baumann@swisscom.com"
          enctype="multipart/form-data"
        >
          <input type="text" name="subject" placeholder="Subject" />
          <textarea
            type="text"
            name="body"
            placeholder="Your message..."
            required
          />
          <input type="submit" value="Send" />
        </form> !-->
        <div class="contact-buttons-container">
          <a
            class="button"
            target="_blank"
            href="https://www.linkedin.com/in/marc-baumann-801ab117b/"
            >LinkedIn</a
          >
          <a
            class="button"
            target="_blank"
            href="https://collaboration.swisscom.com/SwisscomPerson.aspx?accountname=CORPROOT%5CTABBAMA3"
            >Intranet</a
          >
          <a class="button" href="mailto:marc.baumann@swisscom.com">Mail</a>
        </div>
        <p>{{ $t("contact.text") }}</p>
      </div>
      <div class="section hangman">
        <Hangman :lang="lang"></Hangman>
      </div>
    </full-page>
  </div>
</template>

<script>
import Hangman from "@/components/Hangman";
import timelineJson from "./locales/timeline.json";
import VueFullPage from "vue-fullpage.js";
import Vue from "vue";

Vue.use(VueFullPage);

export default {
  name: "App",
  components: { Hangman },
  data() {
    return {
      lang: localStorage.lang,
      search: "",
      skillFilters: [
        "Programmiersprache",
        "Datenbanksprache",
        "Auszeichnungssprache",
        "Notationssprache",
        "Framework",
        "Styling-Sprache",
        "Arbeitsmethode",
      ],
      selectedFilter: this.$t("skills.filter"),
      skills: "",
      projects: "",
      timeline: timelineJson,
      options: {
        normalScrollElements: ".dropdown, .card",
        afterLoad: function(origin, destination) {
          if (destination.anchor == "contact") {
            // eslint-disable-next-line no-undef
            fullpage_api.setAllowScrolling(false, "down");
            // eslint-disable-next-line no-undef
            fullpage_api.setKeyboardScrolling(false, "down");
          } else {
            // eslint-disable-next-line no-undef
            fullpage_api.setAllowScrolling(true);
            // eslint-disable-next-line no-undef
            fullpage_api.setKeyboardScrolling(true);
          }
        },
        menu: "#nav",
        anchors: ["home", "about", "projects", "skills", "contact", "hangman"],
        sectionsColor: [
          "#41b883",
          "#ff5f45",
          "#0798ec",
          "#ecc74a",
          "#7D3EB3",
          "#333333",
        ],
      },
    };
  },
  created() {
    this.skills = require("./locales/" + localStorage.lang + "/skills.json");
    this.projects = require("./locales/" +
      localStorage.lang +
      "/projects.json");
  },
  methods: {
    changeLanguage(lang) {
      localStorage.setItem("lang", lang);
      location.reload();
    },
    generateFilter() {
      let filters = [];
      this.skills.forEach((element) => {
        if (!filters.includes(element.type) && element.type != "") {
          filters.push(element.type);
        }
      });
      return filters;
    },
    checkSearch() {
      if (this.search == "hangman") {
        // eslint-disable-next-line no-undef
        fullpage_api.moveTo(6);
        this.search = "";
      }
    },
    checkFilters(skill) {
      if (skill.name.toLowerCase().includes(this.search.toLowerCase())) {
        if (this.selectedFilter == this.$t("skills.filter")) {
          return true;
        } else if (skill.type == this.selectedFilter) {
          return true;
        }
      }
      return false;
    },
    afterLoad() {},
  },
};

window.addEventListener("hashchange", () => {
  let links = [
    document.getElementById("nav-home"),
    document.getElementById("nav-about"),
    document.getElementById("nav-projects"),
    document.getElementById("nav-skills"),
    document.getElementById("nav-contact"),
  ];
  links.forEach((link) => {
    link.classList.remove("blob-nav");
    if (window.location.hash.includes(link.id.substr(4))) {
      link.classList.add("blob-nav");
    }
  });
});

window.addEventListener("load", () => {
  let links = [
    document.getElementById("nav-home"),
    document.getElementById("nav-about"),
    document.getElementById("nav-projects"),
    document.getElementById("nav-skills"),
    document.getElementById("nav-contact"),
  ];
  links.forEach((link) => {
    link.classList.remove("blob-nav");
    if (window.location.hash.includes(link.id.substr(4))) {
      link.classList.add("blob-nav");
    }
  });
});
</script>

<style src="./App.scss" lang="scss" scoped />
